import base64
import pickle


class SafeUnpickler(pickle.Unpickler):
    """Custom unpickler that only allows safe types to be deserialized."""

    # Whitelist of allowed classes for deserialization
    SAFE_TYPES = {
        'dict', 'list', 'tuple', 'str', 'int', 'float', 'bool', 'NoneType',
        'set', 'frozenset'
    }

    def find_class(self, module, name):
        # Only allow safe built-in types
        if module == '__main__' or module.startswith('builtins.'):
            type_name = name if '.' not in name else name.split('.')[-1]
            if type_name in self.SAFE_TYPES:
                return super().find_class(module, name)

        # Disallow any other class
        raise pickle.UnpicklingError(
            f"Unsafe deserialization attempt: '{module}.{name}' is not allowed"
        )


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings

    Raises:
        ValueError: If the cookie data is invalid or cannot be safely deserialized
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)
    except Exception as e:
        raise ValueError(f"Invalid base64 encoding: {e}")

    try:
        # Deserialize the preferences using safe unpickler
        import io
        unpickler = SafeUnpickler(io.BytesIO(decoded_data))
        preferences = unpickler.load()
    except Exception as e:
        raise ValueError(f"Failed to deserialize preferences: {e}")

    # Validate that the result is a dictionary
    if not isinstance(preferences, dict):
        raise ValueError(
            f"Expected dict, got {type(preferences).__name__}"
        )

    return preferences

